// Search functionality for CURSED documentation

// This file is generated by the documentation system
// The searchIndex is injected by the HTML generator

function initializeSearch() {
    if (typeof window.searchIndex === 'undefined') {
        console.warn('Search index not found');
        return;
    }

    console.log(`Search index loaded with ${window.searchIndex.length} items`);
    
    // Additional search configuration can go here
    const searchConfig = {
        maxResults: 10,
        minQueryLength: 2,
        fuzzyThreshold: 0.6,
        searchFields: ['name', 'description', 'module', 'keywords'],
        weights: {
            exactNameMatch: 100,
            partialNameMatch: 50,
            kindMatch: 30,
            descriptionMatch: 20,
            moduleMatch: 15,
            keywordMatch: 10
        }
    };

    window.searchConfig = searchConfig;
}

// Initialize when this script loads
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initializeSearch);
} else {
    initializeSearch();
}
